const puppeteer = require('puppeteer-core');
const QRCode = require('qrcode');
const path = require('path');
const fs = require('fs').promises;
const { db } = require('../config/database');

class ShareController {
  // 生成战果图
  static generateBattleResult = async (req, res) => {
    try {
      const { userId, username, displayName, avatar, alliance, stats, mapData, timestamp } = req.body;

      // 生成HTML模板
      const html = await this.generateBattleResultHTML({
        username: displayName || username,
        avatar,
        alliance,
        stats,
        mapData,
        timestamp
      });

      // 使用Puppeteer生成图片
      const imageBuffer = await this.generateImageFromHTML(html);

      // 保存图片到服务器
      const fileName = `battle-result-${userId}-${Date.now()}.png`;
      const filePath = path.join(__dirname, '../../public/uploads', fileName);
      
      // 确保上传目录存在
      const uploadDir = path.dirname(filePath);
      await fs.mkdir(uploadDir, { recursive: true });
      
      await fs.writeFile(filePath, imageBuffer);

      // 返回图片URL
      const imageUrl = `${req.protocol}://${req.get('host')}/uploads/${fileName}`;

      res.json({
        success: true,
        imageUrl
      });

    } catch (error) {
      console.error('生成战果图失败:', error);
      res.status(500).json({
        success: false,
        error: '生成战果图失败'
      });
    }
  }

  // 生成战果图HTML模板
  static async generateBattleResultHTML(data) {
    const { username, avatar, alliance, stats, mapData, timestamp } = data;

    return `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="UTF-8">
        <style>
          body {
            margin: 0;
            padding: 0;
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            width: 800px;
            height: 600px;
            overflow: hidden;
          }
          
          .container {
            width: 100%;
            height: 100%;
            position: relative;
            display: flex;
            flex-direction: column;
          }
          
          .header {
            background: rgba(255, 255, 255, 0.95);
            backdrop-filter: blur(20px);
            padding: 20px;
            border-radius: 0 0 20px 20px;
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
          }
          
          .user-info {
            display: flex;
            align-items: center;
            gap: 15px;
            margin-bottom: 15px;
          }
          
          .avatar {
            width: 60px;
            height: 60px;
            border-radius: 50%;
            background: ${avatar ? `url(${avatar})` : 'linear-gradient(45deg, #ff6b6b, #4ecdc4)'};
            background-size: cover;
            background-position: center;
            border: 3px solid #fff;
            box-shadow: 0 4px 15px rgba(0, 0, 0, 0.2);
          }
          
          .user-details {
            flex: 1;
          }
          
          .username {
            font-size: 24px;
            font-weight: bold;
            color: #2d3748;
            margin-bottom: 5px;
          }
          
          .alliance {
            display: flex;
            align-items: center;
            gap: 8px;
            font-size: 16px;
            color: #718096;
          }
          
          .alliance-flag {
            font-size: 20px;
          }
          
          .stats-grid {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 15px;
            margin-top: 15px;
          }
          
          .stat-item {
            text-align: center;
            padding: 15px;
            background: rgba(255, 255, 255, 0.8);
            border-radius: 12px;
            backdrop-filter: blur(10px);
          }
          
          .stat-value {
            font-size: 28px;
            font-weight: bold;
            color: #2d3748;
            margin-bottom: 5px;
          }
          
          .stat-label {
            font-size: 12px;
            color: #718096;
            text-transform: uppercase;
            letter-spacing: 0.5px;
          }
          
          .map-section {
            flex: 1;
            margin: 20px;
            background: rgba(255, 255, 255, 0.9);
            border-radius: 20px;
            padding: 20px;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
          }
          
          .map-placeholder {
            width: 100%;
            height: 200px;
            background: linear-gradient(45deg, #e2e8f0, #cbd5e0);
            border-radius: 15px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 18px;
            color: #4a5568;
            margin-bottom: 20px;
          }
          
          .qr-section {
            position: absolute;
            bottom: 20px;
            right: 20px;
            background: white;
            padding: 15px;
            border-radius: 15px;
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
            text-align: center;
          }
          
          .qr-code {
            width: 80px;
            height: 80px;
            background: #f7fafc;
            border-radius: 8px;
            margin-bottom: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 12px;
            color: #718096;
          }
          
          .qr-text {
            font-size: 10px;
            color: #a0aec0;
            font-weight: 500;
          }
          
          .timestamp {
            position: absolute;
            bottom: 20px;
            left: 20px;
            font-size: 12px;
            color: rgba(255, 255, 255, 0.8);
            background: rgba(0, 0, 0, 0.3);
            padding: 8px 12px;
            border-radius: 20px;
            backdrop-filter: blur(10px);
          }
        </style>
      </head>
      <body>
        <div class="container">
          <div class="header">
            <div class="user-info">
              <div class="avatar"></div>
              <div class="user-details">
                <div class="username">${username}</div>
                ${alliance ? `
                  <div class="alliance">
                    <span class="alliance-flag">${alliance.flag}</span>
                    <span>${alliance.name}</span>
                  </div>
                ` : ''}
              </div>
            </div>
            
            <div class="stats-grid">
              <div class="stat-item">
                <div class="stat-value">${stats.sessionPixels}</div>
                <div class="stat-label">本次绘制</div>
              </div>
              <div class="stat-item">
                <div class="stat-value">${stats.totalPixels}</div>
                <div class="stat-label">总绘制</div>
              </div>
              <div class="stat-item">
                <div class="stat-value">${Math.floor(stats.drawTime / 60)}:${(stats.drawTime % 60).toString().padStart(2, '0')}</div>
                <div class="stat-label">绘制时长</div>
              </div>
              <div class="stat-item">
                <div class="stat-value">${stats.currentPixels}</div>
                <div class="stat-label">当前占领</div>
              </div>
            </div>
          </div>
          
          <div class="map-section">
            <div class="map-placeholder">
              🗺️ 地图区域 (${mapData.center.lat.toFixed(4)}, ${mapData.center.lng.toFixed(4)})
            </div>
            <div style="font-size: 16px; color: #4a5568; text-align: center;">
              在像素战争中绘制了 ${stats.sessionPixels} 个像素点
            </div>
          </div>
          
          <div class="qr-section">
            <div class="qr-code">QR</div>
            <div class="qr-text">扫码参与</div>
          </div>
          
          <div class="timestamp">
            ${new Date(timestamp).toLocaleString('zh-CN')}
          </div>
        </div>
      </body>
      </html>
    `;
  }

  // 使用Puppeteer生成图片
  static async generateImageFromHTML(html) {
    let browser;
    try {
      // 尝试使用系统已安装的Chrome
      browser = await puppeteer.launch({
        headless: true,
        executablePath: process.env.CHROME_PATH || 'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
        args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage']
      });

      const page = await browser.newPage();
      await page.setViewport({ width: 800, height: 600 });
      await page.setContent(html, { waitUntil: 'networkidle0' });
      
      const screenshot = await page.screenshot({
        type: 'png',
        fullPage: false
      });

      return screenshot;
    } catch (error) {
      console.error('Puppeteer启动失败，尝试备用方案:', error);
      
      // 备用方案：生成简单的HTML文件供用户下载
      const fallbackHtml = `
        <!DOCTYPE html>
        <html>
        <head>
          <meta charset="UTF-8">
          <title>战果图生成失败</title>
          <style>
            body { font-family: Arial, sans-serif; padding: 20px; }
            .error { color: red; }
          </style>
        </head>
        <body>
          <h1>战果图生成失败</h1>
          <p class="error">由于技术原因，无法生成图片。请稍后重试。</p>
          <p>错误信息: ${error.message}</p>
        </body>
        </html>
      `;
      
      return Buffer.from(fallbackHtml, 'utf-8');
    } finally {
      if (browser) {
        await browser.close();
      }
    }
  }

  // 生成二维码
  static generateQRCode = async (req, res) => {
    try {
      const { text, width, height, color, backgroundColor } = req.body;

      const qrCodeDataURL = await QRCode.toDataURL(text, {
        width: width || 200,
        height: height || 200,
        color: {
          dark: color || '#000000',
          light: backgroundColor || '#FFFFFF'
        },
        margin: 2
      });

      res.json({
        success: true,
        qrCodeUrl: qrCodeDataURL
      });

    } catch (error) {
      console.error('生成二维码失败:', error);
      res.status(500).json({
        success: false,
        error: '生成二维码失败'
      });
    }
  }

  // 获取分享统计
  static getShareStats = async (req, res) => {
    try {
      const userId = req.user.id;

      const stats = await db('user_shares')
        .where('user_id', userId)
        .select('platform', 'created_at');

      const totalShares = stats.length;
      const platformStats = {
        wechat: stats.filter(s => s.platform === 'wechat').length,
        weibo: stats.filter(s => s.platform === 'weibo').length,
        douyin: stats.filter(s => s.platform === 'douyin').length,
        xiaohongshu: stats.filter(s => s.platform === 'xiaohongshu').length
      };

      const lastShare = stats.length > 0 ? stats[stats.length - 1].created_at : null;

      res.json({
        success: true,
        totalShares,
        platformStats,
        lastShareTime: lastShare
      });

    } catch (error) {
      console.error('获取分享统计失败:', error);
      res.status(500).json({
        success: false,
        error: '获取分享统计失败'
      });
    }
  }

  // 记录分享行为
  static recordShare = async (req, res) => {
    try {
      const userId = req.user.id;
      const { platform, imageUrl, timestamp } = req.body;

      await db('user_shares').insert({
        user_id: userId,
        platform,
        image_url: imageUrl,
        created_at: timestamp || new Date()
      });

      res.json({
        success: true,
        message: '分享记录已保存'
      });

    } catch (error) {
      console.error('记录分享失败:', error);
      res.status(500).json({
        success: false,
        error: '记录分享失败'
      });
    }
  }
}

module.exports = {
  generateBattleResult: ShareController.generateBattleResult,
  generateQRCode: ShareController.generateQRCode,
  getShareStats: ShareController.getShareStats,
  recordShare: ShareController.recordShare
};